// 1) Set APPROVAL_URL to your ngrok/public API. 2) WEBHOOK_SECRET must EXACTLY match CUSTOMER_APPROVAL_WEBHOOK_SECRET in backend/.env (restart uvicorn after changing .env).
const APPROVAL_URL = 'https://YOUR-NGROK-SUBDOMAIN.ngrok-free.app/api/approval';
let WEBHOOK_SECRET = 'REPLACE_WITH_CUSTOMER_APPROVAL_WEBHOOK_SECRET';
try {
  if (typeof $env !== 'undefined' && $env.CUSTOMER_APPROVAL_WEBHOOK_SECRET) {
    WEBHOOK_SECRET = String($env.CUSTOMER_APPROVAL_WEBHOOK_SECRET).trim();
  }
} catch (e) {}
WEBHOOK_SECRET = String(WEBHOOK_SECRET).trim();
if (!WEBHOOK_SECRET || WEBHOOK_SECRET.startsWith('REPLACE')) {
  throw new Error('Set WEBHOOK_SECRET to the same value as CUSTOMER_APPROVAL_WEBHOOK_SECRET in backend/.env (or set n8n env CUSTOMER_APPROVAL_WEBHOOK_SECRET).');
}

const UUID = /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i;

function extractBoqVersionId(j) {
  const subject = String(j.subject || '');
  const ref = subject.match(/ref:([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i);
  if (ref) return ref[1];
  const text = [subject, j.snippet, j.textPlain, j.text, j.plainText, j.html, j.textHtml, JSON.stringify(j)]
    .filter(Boolean)
    .join('\n');
  const tagged = text.match(/ALUFIT_BOQ_VERSION_ID=([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i);
  if (tagged) return tagged[1];
  const legacy = text.match(/BOQ version ID:\s*([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i);
  if (legacy) return legacy[1];
  const any = text.match(UUID);
  return any ? any[1] : null;
}

const out = [];
for (const item of $input.all()) {
  const j = item.json;
  const boq_version_id = extractBoqVersionId(j);
  if (!boq_version_id) {
    throw new Error('No BOQ UUID found. Use Alufit emails with "| ref:<uuid>" in the subject, or ensure the full message includes ALUFIT_BOQ_VERSION_ID= / BOQ version ID: (Gmail snippet omits most of the body).');
  }
  let body;
  try {
    body = await this.helpers.httpRequest({
      method: 'POST',
      url: APPROVAL_URL,
      headers: {
        'X-Webhook-Secret': WEBHOOK_SECRET,
        'x-webhook-secret': WEBHOOK_SECRET,
      },
      body: {
        boq_version_id,
        status: 'approved',
        note: 'Confirmed via Gmail (n8n)',
      },
      json: true,
    });
  } catch (err) {
    const detail = err.response?.body ?? err.message ?? String(err);
    throw new Error(`Alufit API request failed: ${typeof detail === 'string' ? detail : JSON.stringify(detail)}`);
  }
  out.push({ json: { ...j, boq_version_id, approval_api_response: body } });
}
return out;
